const Mustache = require('mustache');
return items.map(item => {
  const r = item.json;
  const view = { vendor: r.vendor, amount: Number(r.amount).toFixed(2), raw_id: r.raw_id, due_date: r.due_date, description: r.description || '' };
  const html = Mustache.render(r.body, view);
  return { json: { to: 'finanzas@tuempresa.com', subject: r.title.replace('{{vendor}}', r.vendor), html } };
});
